{
  size_t ss_size;
  const ADDRINFOEXW_ *ai;
  struct Curl_addrinfo *ca;
  struct Curl_addrinfo *cafirst = NULL;
  struct Curl_addrinfo *calast = NULL;
#ifdef __clang__
#pragma clang diagnostic push
#pragma clang diagnostic ignored "-Wcast-align"
#endif
  struct thread_sync_data *tsd =
    CONTAINING_RECORD(overlapped, struct thread_sync_data, w8.overlapped);
#ifdef __clang__
#pragma clang diagnostic pop
#endif
  struct thread_data *td = tsd->td;
  const ADDRINFOEXW_ *res = tsd->w8.res;
  int error = (int)err;
  (void)bytes;

  if(error == ERROR_SUCCESS) {
    /* traverse the addrinfo list */

    for(ai = res; ai != NULL; ai = ai->ai_next) {
      size_t namelen = ai->ai_canonname ? wcslen(ai->ai_canonname) + 1 : 0;
      /* ignore elements with unsupported address family, */
      /* settle family-specific sockaddr structure size.  */
      if(ai->ai_family == AF_INET)
        ss_size = sizeof(struct sockaddr_in);
#ifdef ENABLE_IPV6
      else if(ai->ai_family == AF_INET6)
        ss_size = sizeof(struct sockaddr_in6);
#endif
      else
        continue;

      /* ignore elements without required address info */
      if(!ai->ai_addr || !(ai->ai_addrlen > 0))
        continue;

      /* ignore elements with bogus address size */
      if((size_t)ai->ai_addrlen < ss_size)
        continue;

      ca = malloc(sizeof(struct Curl_addrinfo) + ss_size + namelen);
      if(!ca) {
        error = EAI_MEMORY;
        break;
      }

      /* copy each structure member individually, member ordering, */
      /* size, or padding might be different for each platform.    */
      ca->ai_flags     = ai->ai_flags;
      ca->ai_family    = ai->ai_family;
      ca->ai_socktype  = ai->ai_socktype;
      ca->ai_protocol  = ai->ai_protocol;
      ca->ai_addrlen   = (curl_socklen_t)ss_size;
      ca->ai_addr      = NULL;
      ca->ai_canonname = NULL;
      ca->ai_next      = NULL;

      ca->ai_addr = (void *)((char *)ca + sizeof(struct Curl_addrinfo));
      memcpy(ca->ai_addr, ai->ai_addr, ss_size);

      if(namelen) {
        size_t i;
        ca->ai_canonname = (void *)((char *)ca->ai_addr + ss_size);
        for(i = 0; i < namelen; ++i) /* convert wide string to ascii */
          ca->ai_canonname[i] = (char)ai->ai_canonname[i];
        ca->ai_canonname[namelen] = '\0';
      }

      /* if the return list is empty, this becomes the first element */
      if(!cafirst)
        cafirst = ca;

      /* add this element last in the return list */
      if(calast)
        calast->ai_next = ca;
      calast = ca;
    }

    /* if we failed, also destroy the Curl_addrinfo list */
    if(error) {
      Curl_freeaddrinfo(cafirst);
      cafirst = NULL;
    }
    else if(!cafirst) {
#ifdef EAI_NONAME
      /* rfc3493 conformant */
      error = EAI_NONAME;
#else
      /* rfc3493 obsoleted */
      error = EAI_NODATA;
#endif
#ifdef USE_WINSOCK
      SET_SOCKERRNO(error);
#endif
    }
    tsd->res = cafirst;
  }

  if(tsd->w8.res) {
    Curl_FreeAddrInfoExW(tsd->w8.res);
    tsd->w8.res = NULL;
  }

  if(error) {
    tsd->sock_error = SOCKERRNO?SOCKERRNO:error;
    if(tsd->sock_error == 0)
      tsd->sock_error = RESOLVER_ENOMEM;
  }
  else {
    Curl_addrinfo_set_port(tsd->res, tsd->port);
  }

  Curl_mutex_acquire(tsd->mtx);
  if(tsd->done) {
    /* too late, gotta clean up the mess */
    Curl_mutex_release(tsd->mtx);
    destroy_thread_sync_data(tsd);
    free(td);
  }
  else {
#ifndef CURL_DISABLE_SOCKETPAIR
    char buf[1];
    if(tsd->sock_pair[1] != CURL_SOCKET_BAD) {
      /* DNS has been resolved, signal client task */
      buf[0] = 1;
      if(swrite(tsd->sock_pair[1],  buf, sizeof(buf)) < 0) {
        /* update sock_erro to errno */
        tsd->sock_error = SOCKERRNO;
      }
    }
#endif
    tsd->done = 1;
    Curl_mutex_release(tsd->mtx);
    if(td->complete_ev)
      SetEvent(td->complete_ev); /* Notify caller that the query completed */
  }
}

{
